use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use crate::projector::{
    traits::{Project, Reconstruct, PartialProject, ProjectorConfig},
    BaseProjector,
};
use crate::preprocessing::{Preprocessor, Center, Standardize, PreprocessPipeline};
use crate::svd::{SvdMethod, SvdConfig, svd_factory};
use serde::{Serialize, Deserialize};
use std::fmt;

/// Principal Component Analysis (PCA)
/// 
/// PCA is a statistical procedure that uses an orthogonal transformation to convert
/// a set of observations of possibly correlated variables into a set of values of
/// linearly uncorrelated variables called principal components.
#[derive(Debug, Clone)]
pub struct Pca {
    /// Base projector containing the projection matrix
    base_projector: BaseProjector,

    /// Singular values from SVD
    singular_values: Vector,

    /// Standard deviations of components
    standard_deviations: Vector,

    /// Explained variance ratio for each component
    explained_variance_ratio: Vector,

    /// Cumulative explained variance ratio
    cumulative_variance_ratio: Vector,

    /// Total variance in the original data
    total_variance: f64,

    /// Number of samples used for fitting
    n_samples: usize,

    /// Preprocessing pipeline
    preprocessor: Option<PreprocessPipeline>,

    /// SVD method used
    svd_method: SvdMethod,

    /// Configuration
    config: PcaConfig,
}

/// Configuration for PCA
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PcaConfig {
    /// Base projector configuration
    pub projector_config: ProjectorConfig,

    /// SVD method to use
    pub svd_method: SvdMethod,

    /// SVD configuration
    pub svd_config: SvdConfig,

    /// Whether to use correlation matrix (standardize) or covariance matrix (center only)
    pub use_correlation: bool,

    /// Minimum variance to retain (between 0 and 1)
    pub min_variance_retained: Option<f64>,

    /// Whether to compute all components or just the requested number
    pub compute_all_components: bool,
}

impl Default for PcaConfig {
    fn default() -> Self {
        Self {
            projector_config: ProjectorConfig::default(),
            svd_method: SvdMethod::Auto,
            svd_config: SvdConfig::default(),
            use_correlation: false,
            min_variance_retained: None,
            compute_all_components: false,
        }
    }
}

impl Pca {
    /// Create a new unfitted PCA instance
    pub fn new(config: PcaConfig) -> Self {
        let n_features = 0;
        let n_components = config.projector_config.n_components.unwrap_or(0);

        Self {
            base_projector: BaseProjector::new_unfitted(n_features, n_components, config.projector_config.clone()),
            singular_values: Vector::zeros(0),
            standard_deviations: Vector::zeros(0),
            explained_variance_ratio: Vector::zeros(0),
            cumulative_variance_ratio: Vector::zeros(0),
            total_variance: 0.0,
            n_samples: 0,
            preprocessor: None,
            svd_method: config.svd_method,

