   154→        let mut svd_config = self.config.svd_config.clone();
   155→        svd_config.n_components = Some(n_components);
   156→        
   157→        // Select SVD method
   158→        let svd_method = if self.config.svd_method == SvdMethod::Auto {
   159→            // Auto-select based on matrix size
   160→            if n_samples * n_features < 1000 {
