    /// Get total variance in the original data
    pub fn total_variance(&self) -> f64 {
        self.total_variance
    }

    /// Truncate PCA to retain only the first k components
    pub fn truncate(&mut self, k: usize) -> Result<(), MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        if k == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "k".to_string(),
                value: k.to_string(),
                reason: "must be at least 1".to_string(),
            });
        }

        if k > self.n_components() {
            return Err(MultivariousError::InvalidParameter {
                name: "k".to_string(),
                value: k.to_string(),
                reason: format!("exceeds current number of components ({})", self.n_components()),
            });
        }

        if k == self.n_components() {
            return Ok(()); // Nothing to truncate
        }

        // Truncate the projection matrix
        let projection_matrix = self.base_projector.projection_matrix();
        let truncated_matrix = projection_matrix.slice(ndarray::s![.., ..k]).to_owned();

        // Create new base projector with truncated matrix
        self.base_projector = BaseProjector::new(truncated_matrix, self.config.projector_config.clone())?;

        // Truncate variance arrays
        self.singular_values = self.singular_values.slice(ndarray::s![..k]).to_owned();
        self.standard_deviations = self.standard_deviations.slice(ndarray::s![..k]).to_owned();
        self.explained_variance_ratio = self.explained_variance_ratio.slice(ndarray::s![..k]).to_owned();
        self.cumulative_variance_ratio = self.cumulative_variance_ratio.slice(ndarray::s![..k]).to_owned();

        Ok(())
    }

    /// Automatically select the number of components based on a selection criterion
    pub fn auto_select_components(&mut self, criterion: ComponentSelectionCriterion) -> Result<usize, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let n_components = match criterion {
            ComponentSelectionCriterion::VarianceThreshold(threshold) => {
                self.n_components_for_variance(threshold)?
            }
            ComponentSelectionCriterion::Kaiser => {
                self.kaiser_criterion()?
            }
            ComponentSelectionCriterion::Elbow => {
                self.elbow_point()?
            }
            ComponentSelectionCriterion::FixedNumber(n) => {
                n.min(self.n_components())
            }
        };

        self.truncate(n_components)?;
        Ok(n_components)
    }

    /// Compute Hotelling's T-squared statistic for outlier detection
    pub fn hotelling_t2(&self, data: &Matrix) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Transform data to component space
        let scores = self.transform(data)?;
        let n_samples = scores.nrows();

        // Compute T² for each sample
        let mut t2_values = Vector::zeros(n_samples);

        // Get inverse of eigenvalues (1/variance) for weighting
        let eigenvalues = self.explained_variance()?;

        for i in 0..n_samples {
            let sample_scores = scores.row(i);
            let mut t2 = 0.0;

            // T² = sum((score_j)² / eigenvalue_j)
            for j in 0..self.n_components() {
                if eigenvalues[j] > 1e-10 {
                    t2 += (sample_scores[j] * sample_scores[j]) / eigenvalues[j];
                }
            }

            t2_values[i] = t2;
        }

        Ok(t2_values)
    }

    /// Compute Q-residuals (squared prediction error) for outlier detection
    pub fn q_residuals(&self, data: &Matrix) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Transform and reconstruct
        let transformed = self.transform(data)?;
        let reconstructed = self.inverse_transform(&transformed)?;

        // Compute squared residuals for each sample
        let n_samples = data.nrows();
        let mut q_values = Vector::zeros(n_samples);

        for i in 0..n_samples {
            let residual = &data.row(i) - &reconstructed.row(i);
            q_values[i] = residual.dot(&residual);
        }

        Ok(q_values)
    }

    /// Compute contribution of each variable to each principal component
    pub fn variable_contributions(&self) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let components = self.components()?;
        let n_components = components.nrows();
        let n_features = components.ncols();

        // Contribution = squared loading / sum of squared loadings for that component
        let mut contributions = Matrix::zeros((n_components, n_features));

        for i in 0..n_components {
            let component = components.row(i);
            let sum_sq = component.dot(&component);

            if sum_sq > 1e-10 {
                for j in 0..n_features {
                    contributions[[i, j]] = (component[j] * component[j]) / sum_sq;
                }
            }
        }

        Ok(contributions)
    }

    /// Compute contribution of each sample to each principal component
    pub fn sample_contributions(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        let scores = self.transform(data)?;
        let n_samples = scores.nrows();
        let n_components = scores.ncols();

        // Contribution = squared score / (n_samples * eigenvalue)
        let eigenvalues = self.explained_variance()?;
        let mut contributions = Matrix::zeros((n_samples, n_components));

        for j in 0..n_components {
            if eigenvalues[j] > 1e-10 {
                let scale = (n_samples as f64) * eigenvalues[j];
                for i in 0..n_samples {
                    contributions[[i, j]] = (scores[[i, j]] * scores[[i, j]]) / scale;
                }
            }
        }

        Ok(contributions)
    }
