    #[test]
    fn test_auto_select_components() {
        let data = array![
            [1.0, 0.0, 0.0],
            [2.0, 0.1, 0.0],
            [3.0, 0.0, 0.1],
            [4.0, 0.1, 0.0],
            [5.0, 0.0, 0.1],
        ];

        // Test variance threshold
        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();
        let n_selected = pca.auto_select_components(ComponentSelectionCriterion::VarianceThreshold(0.9)).unwrap();
        assert!(n_selected >= 1 && n_selected <= 3);

        // Test fixed number
        let mut pca2 = PcaBuilder::new().build();
        pca2.fit(&data).unwrap();
        let n_fixed = pca2.auto_select_components(ComponentSelectionCriterion::FixedNumber(2)).unwrap();
        assert_eq!(n_fixed, 2);
        assert_eq!(pca2.n_components(), 2);
    }

    #[test]
    fn test_outlier_detection() {
        let data = array![
            [1.0, 1.0],
            [2.0, 2.0],
            [3.0, 3.0],
            [10.0, 10.0], // Outlier
        ];

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test Hotelling T²
        let t2 = pca.hotelling_t2(&data).unwrap();
        assert_eq!(t2.len(), 4);
        // Last sample should have highest T² value
        assert!(t2[3] > t2[0]);
        assert!(t2[3] > t2[1]);
        assert!(t2[3] > t2[2]);

        // Test Q-residuals
        let q = pca.q_residuals(&data).unwrap();
        assert_eq!(q.len(), 4);
        // For perfect linear data, residuals should be very small
        for i in 0..3 {
            assert!(q[i] < 0.1);
        }
    }

    #[test]
    fn test_contributions() {
        let data = array![
            [1.0, 2.0, 3.0],
            [2.0, 4.0, 6.0],
            [3.0, 6.0, 9.0],
            [4.0, 8.0, 12.0],
        ];

        let mut pca = PcaBuilder::new().build();
        pca.fit(&data).unwrap();

        // Test variable contributions
        let var_contrib = pca.variable_contributions().unwrap();
        assert_eq!(var_contrib.shape(), &[3, 3]); // n_components x n_features

        // Each row should sum to approximately 1 (contributions to each PC)
        for i in 0..3 {
            let row_sum: f64 = var_contrib.row(i).sum();
            assert!((row_sum - 1.0).abs() < 0.01);
        }

        // Test sample contributions
        let sample_contrib = pca.sample_contributions(&data).unwrap();
        assert_eq!(sample_contrib.shape(), &[4, 3]); // n_samples x n_components

        // All contributions should be non-negative
        for val in sample_contrib.iter() {
            assert!(*val >= 0.0);
        }
    }

    #[test]
    fn test_diagnostic_errors() {
        let mut pca = PcaBuilder::new().build();

        // Not fitted errors
        assert!(pca.truncate(1).is_err());
        assert!(pca.auto_select_components(ComponentSelectionCriterion::Kaiser).is_err());
        assert!(pca.hotelling_t2(&Matrix::zeros((1, 1))).is_err());
        assert!(pca.q_residuals(&Matrix::zeros((1, 1))).is_err());
        assert!(pca.variable_contributions().is_err());
        assert!(pca.sample_contributions(&Matrix::zeros((1, 1))).is_err());
    }
}

